const body = $input.first().json.body || {};
const tz = 'Europe/Prague';
const now = DateTime.now().setZone(tz);

let timeMin, timeMax, preferred_date;

if (body.preferred_date) {
  preferred_date = body.preferred_date;
  const d = DateTime.fromISO(body.preferred_date, { zone: tz });
  timeMin = d.startOf('day').toISO();
  timeMax = d.endOf('day').toISO();
} else {
  preferred_date = null;
  timeMin = now.toISO();
  timeMax = now.plus({ days: 4 }).startOf('day').toISO();
}

return [{ json: { timeMin, timeMax, preferred_date } }];

try {
  const TZ = 'Europe/Prague';
  const businessHoursStart = 9;
  const businessHoursEnd = 17;
  const slotMinutes = 30;
  const maxSlots = 6;

  const range = $('Prepare Range').first().json;

  const events = $input.all().map(i => i.json);
  const busy = events
    .filter(e => e.start && e.end && (e.start.dateTime || e.start.date))
    .map(e => ({
      start: DateTime.fromISO(e.start.dateTime || e.start.date),
      end: DateTime.fromISO(e.end.dateTime || e.end.date)
    }));

  const slots = [];
  const rangeStart = DateTime.fromISO(range.timeMin).setZone(TZ);
  const rangeEnd = DateTime.fromISO(range.timeMax).setZone(TZ);

  let cursor = rangeStart.set({ hour: businessHoursStart, minute: 0, second: 0, millisecond: 0 });
  if (cursor < rangeStart) {
    cursor = rangeStart.startOf('minute');
    const cm = cursor.minute;
    cursor = cursor.set({ minute: cm < 30 ? 30 : 0, second: 0, millisecond: 0 });
    if (cm >= 30) cursor = cursor.plus({ hours: 1 });
  }

  while (cursor < rangeEnd && slots.length < maxSlots) {
    const dow = cursor.weekday;
    const hour = cursor.hour;

    if (dow === 6 || dow === 7) {
      cursor = cursor.plus({ days: 1 }).set({ hour: businessHoursStart, minute: 0, second: 0, millisecond: 0 });
      continue;
    }
    if (hour >= businessHoursEnd) {
      cursor = cursor.plus({ days: 1 }).set({ hour: businessHoursStart, minute: 0, second: 0, millisecond: 0 });
      continue;
    }
    if (hour < businessHoursStart) {
      cursor = cursor.set({ hour: businessHoursStart, minute: 0, second: 0, millisecond: 0 });
      continue;
    }

    const slotStart = cursor;
    const slotEnd = cursor.plus({ minutes: slotMinutes });
    const overlaps = busy.some(b => slotStart < b.end && slotEnd > b.start);

    if (!overlaps) {
      slots.push({
        date: slotStart.toFormat('yyyy-MM-dd'),
        time: slotStart.toFormat('h:mm a'),
        day: slotStart.toFormat('cccc')
      });
    }

    cursor = cursor.plus({ minutes: slotMinutes });
  }

  return [{ json: { available_slots: slots } }];
} catch (err) {
  return [{ json: { available_slots: [], error: String(err) } }];
}
